✅ <strong>One-page format</strong> — clean &amp; recruiter-friendly<br>
✅ <strong>ATS keywords</strong> matched from the job description<br>
✅ <strong>No fabrication</strong> — only your real experience, reframed
</p>
</div>
<p style="font-size:13px;color:#666;line-height:1.7;margin:0 0 8px;">📎 Open the attached <strong>resume.pdf</strong> to review your tailored resume. Good luck with your application to <strong>${esc(companyName)}</strong>! 🚀</p>
<p style="font-size:12px;color:#9d9ab5;margin:24px 0 0;padding-top:16px;border-top:1px solid #e5e1ff;text-align:center;">Built by <strong>Ravinder Singh Negi</strong> · ResumeForge AI</p>
</div></div>`;

return {
  resumeText,
  recipientEmail,
  companyName,
  emailBody,
  subject: `📄 Resume for ${companyName} — ${dateStr} | ResumeForge AI`,
  parsedSections: sections,
  name,
  contactLine
};

const PDFDocument = require('pdfkit');

const meta = $('Prepare Doc Content').item.json;
const resumeText = meta.resumeText || '';
const recipientEmail = meta.recipientEmail || 'rvnegi786@gmail.com';
const subject = meta.subject || 'Your Tailored Resume';
const emailBody = meta.emailBody || '';
const companyName = meta.companyName || '';

function cleanText(t) {
  return (t || '').replace(/```[a-z]*\n?/gi, '').replace(/```/g, '').trim();
}
// Strip ALL markdown: **bold**, *italic*, and lone stray asterisks
function stripAll(s) {
  return String(s)
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .replace(/^\*+\s*/gm, '')
    .replace(/\s*\*+$/gm, '')
    .trim();
}
function toAbsUrl(url) {
  return (url || '').startsWith('http') ? url : 'https://' + url;
}

const SECTIONS = [
  'PROFESSIONAL SUMMARY','TECHNICAL SKILLS','PROFESSIONAL EXPERIENCE',
  'WORK EXPERIENCE','EXPERIENCE','PROJECTS','AWARDS','EDUCATION','SKILLS'
];

const rawLines = cleanText(resumeText).split('\n');
let nameStr = '', contactStr = '', linksStr = '';
let sections = {}, currentSection = '', sectionContent = [];

for (let i = 0; i < rawLines.length; i++) {
  const line = rawLines[i].trim();
  if (!line) continue;
  if (i === 0) { nameStr = stripAll(line); continue; }
  if (i === 1) { contactStr = stripAll(line).replace(/\|/g, '  |  '); continue; }
  if (i === 2 && (line.toLowerCase().includes('linkedin') || line.toLowerCase().includes('github') || line.toLowerCase().includes('vercel'))) {
    linksStr = stripAll(line); continue;
  }
  const upper = line.toUpperCase();
  const matched = SECTIONS.find(s => upper.startsWith(s));
  if (matched) {
    if (currentSection) sections[currentSection] = [...sectionContent];
    currentSection = matched;
    sectionContent = [];
  } else {
    if (currentSection) sectionContent.push(rawLines[i]);
  }
}
if (currentSection) sections[currentSection] = [...sectionContent];

const pdfBuffer = await new Promise((resolve, reject) => {
  const doc = new PDFDocument({
    size: 'A4',
    margins: { top: 48, bottom: 48, left: 56, right: 56 },
    info: { Title: `Resume - ${nameStr}`, Author: nameStr }
  });

  const chunks = [];
  doc.on('data', c => chunks.push(c));
  doc.on('end', () => resolve(Buffer.concat(chunks)));
  doc.on('error', reject);

  const W = doc.page.width;
  const L = 56, R = W - 56;
  const CW = R - L;
  const BLACK = '#000000';

  // Section heading
  function sectionTitle(title) {
    doc.moveDown(0.7);
    doc.font('Helvetica-Bold').fontSize(12).fillColor(BLACK)
      .text(title.toUpperCase(), L, doc.y, { width: CW, characterSpacing: 0.5 });
    const ry = doc.y + 2;
    doc.moveTo(L, ry).lineTo(R, ry).lineWidth(1).strokeColor(BLACK).stroke();
    doc.moveDown(0.5);
  }

  // Left label + right date — tracks cursor properly even if left wraps
  function rowWithDate(left, right, bold = false) {
    const dw = 125, tw = CW - dw;
    const startY = doc.y;
    // Render left text (may wrap to multiple lines)
    doc.font(bold ? 'Helvetica-Bold' : 'Helvetica').fontSize(11).fillColor(BLACK)
      .text(stripAll(left), L, startY, { width: tw });
    const afterLeftY = doc.y;
    // Render right date at the SAME startY, right-aligned, single line
    doc.font('Helvetica-Oblique').fontSize(10).fillColor(BLACK)
      .text(stripAll(right), L + tw, startY, { width: dw, align: 'right', lineBreak: false });
    // Ensure cursor is below the taller of the two
    if (afterLeftY > doc.y) {
      // Move cursor back down to after the left text
      doc.font('Helvetica').fontSize(11).text('', L, afterLeftY, { width: 0 });
    }
    doc.moveDown(0.35);
  }

  // Bullet point
  function bullet(text) {
    const clean = stripAll(text.replace(/^[\-•*]+\s*/, '').trim());
    const startY = doc.y;
    doc.font('Helvetica').fontSize(11).fillColor(BLACK)
      .text('•', L + 2, startY, { width: 14, lineBreak: false })
      .text(clean, L + 16, startY, { width: CW - 16 });
    doc.moveDown(0.22);
  }

  // Plain body
  function body(text) {
    doc.font('Helvetica').fontSize(11).fillColor(BLACK)
      .text(stripAll(text), L, doc.y, { width: CW });
    doc.moveDown(0.22);
  }

  // Skill: Bold label: value
  function skillLine(line) {
    const ci = line.indexOf(':');
    if (ci > -1) {
      const label = stripAll(line.slice(0, ci).trim());
      const value = stripAll(line.slice(ci + 1).trim());
      doc.font('Helvetica-Bold').fontSize(11).fillColor(BLACK)
        .text(label + ': ', L, doc.y, { continued: true })
        .font('Helvetica').text(value, { width: CW });
    } else {
      body(line);
    }
    doc.moveDown(0.15);
  }

  // Project line with smart URL placement
  function projectLine(line) {
    // Strip leading bullet chars
    const isBullet = /^[•\-*]/.test(line.trim());
    let content = isBullet ? line.trim().replace(/^[•\-*]+\s*/, '') : line.trim();
    content = stripAll(content);

    // Extract trailing URL (handles github.com/... style and hisabkar.vercel.app etc.)
    const urlRegex = /\s+(https?:\/\/\S+|[\w.\-]+\.(?:app|io|com|net|org|dev|in)[\/\w.\-#?&=%]*)\s*[|]?\s*$/;
    const urlMatch = content.match(urlRegex);
    const rawUrl = urlMatch ? urlMatch[1].replace(/[|\s]+$/, '') : null;
    // Remove the URL (and any trailing |) from mainPart
    let mainPart = rawUrl
      ? content.slice(0, content.indexOf(urlMatch[0])).replace(/\s*[|]\s*$/, '').trim()
      : content.replace(/\s*[|]\s*$/, '').trim();
    mainPart = stripAll(mainPart);

    const absUrl = rawUrl ? toAbsUrl(rawUrl) : null;
    const displayUrl = rawUrl ? rawUrl.replace(/^https?:\/\//, '') : null;

    // Detect separator between project name and tech
    const sepMatch = mainPart.match(/\s*(—|\|)\s*/);
    const sepIdx = sepMatch ? mainPart.indexOf(sepMatch[0]) : -1;
    const isProjHeader = sepIdx > -1 || rawUrl;

    if (isProjHeader) {
      const projName = stripAll(sepIdx > -1 ? mainPart.slice(0, sepIdx).trim() : mainPart);
      // Tech: everything after the separator, clean trailing | and stray chars
      const rawTech = sepIdx > -1 ? mainPart.slice(sepIdx + sepMatch[0].length) : '';
      const tech = stripAll(rawTech).replace(/\s*[|,]\s*$/, '').trim();

      const y = doc.y;

      // Measure URL width to decide placement
      doc.font('Helvetica').fontSize(9.5);
      const urlTextW = displayUrl ? doc.widthOfString(displayUrl) : 0;
      // URL fits inline if it's < 40% of content width
      const urlInline = urlTextW > 0 && urlTextW < CW * 0.40;
      const urlW = urlInline ? urlTextW + 6 : 0;
      const leftW = CW - (urlInline ? urlW + 4 : 0);

      // Render project name (bold)
      doc.font('Helvetica-Bold').fontSize(11).fillColor(BLACK)
        .text('• ' + projName, L, y, { width: leftW, continued: !!tech, lineBreak: false });
      if (tech) {
        doc.font('Helvetica').fontSize(10.5).fillColor(BLACK)
          .text('  —  ' + tech, { lineBreak: false });
      }

      // URL placement
      if (displayUrl && absUrl) {
        if (urlInline) {
          // Short URL: right-align on project name line
          const urlX = R - urlTextW - 2;
          doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
            .text(displayUrl, urlX, y, { width: urlTextW + 4, align: 'right', link: absUrl, underline: true, lineBreak: false });
        } else {
          // Long URL (e.g. github.com/user/very-long-repo): place on next line, right-aligned
          doc.font('Helvetica').fontSize(9).fillColor(BLACK)
            .text(displayUrl, L, doc.y + 1, { width: CW, align: 'right', link: absUrl, underline: true });
        }
      }
      doc.moveDown(0.3);
    } else {
      // Description line under a project (indented)
      doc.font('Helvetica').fontSize(11).fillColor(BLACK)
        .text(content, L + 16, doc.y, { width: CW - 16 });
      doc.moveDown(0.2);
    }
  }

  // ══ HEADER ═════════════════════════════════════════════════════════════
  doc.font('Helvetica-Bold').fontSize(20).fillColor(BLACK)
    .text(nameStr, L, 48, { width: CW, align: 'center' });
  doc.moveDown(0.3);

  doc.font('Helvetica').fontSize(10.5).fillColor(BLACK)
    .text(contactStr, L, doc.y, { width: CW, align: 'center' });
  doc.moveDown(0.25);

  // Clickable links row
  if (linksStr) {
    const links = linksStr.split('|').map(l => stripAll(l.trim())).filter(Boolean);
    const y = doc.y;
    const totalText = links.join('  |  ');
    doc.font('Helvetica').fontSize(10.5).fillColor(BLACK);
    const lineW = doc.widthOfString(totalText);
    let curX = L + (CW - lineW) / 2;
    links.forEach((link, i) => {
      const absLink = toAbsUrl(link);
      const w = doc.widthOfString(link);
      doc.text(link, curX, y, { width: w + 2, continued: false, link: absLink, underline: true });
      curX += w;
      if (i < links.length - 1) {
        const sw = doc.widthOfString('  |  ');
        doc.text('  |  ', curX, y, { continued: false });
        curX += sw;
      }
    });
    doc.moveDown(0.4);
  }

  doc.moveTo(L, doc.y).lineTo(R, doc.y).lineWidth(1).strokeColor(BLACK).stroke();
  doc.moveDown(0.3);

  // ══ PROFESSIONAL SUMMARY
  const summary = sections['PROFESSIONAL SUMMARY'] || [];
  if (summary.length) {
    sectionTitle('Professional Summary');
    summary.forEach(l => { if (l.trim()) body(l); });
  }

  // ══ TECHNICAL SKILLS
  const skills = sections['TECHNICAL SKILLS'] || sections['SKILLS'] || [];
  if (skills.length) {
    sectionTitle('Technical Skills');
    skills.forEach(l => { if (l.trim()) skillLine(stripAll(l.trim())); });
  }

  // ══ PROFESSIONAL EXPERIENCE
  const exp = sections['PROFESSIONAL EXPERIENCE'] || sections['WORK EXPERIENCE'] || sections['EXPERIENCE'] || [];
  if (exp.length) {
    sectionTitle('Professional Experience');
    exp.forEach(line => {
      const raw = line.trim();
      if (!raw) return;
      const t = stripAll(raw);
      if ((t.includes('|') || t.includes('—')) && (t.includes('20') || t.toLowerCase().includes('present'))) {
        const sep = t.includes('|') ? '|' : '—';
        const parts = t.split(sep);
        rowWithDate(parts.slice(0, -1).join(sep).trim(), parts[parts.length - 1].trim(), true);
      } else if (/^[•\-*]/.test(raw)) {
        bullet(raw);
      } else {
        doc.font('Helvetica').fontSize(10.5).fillColor(BLACK)
          .text(t, L, doc.y, { width: CW });
        doc.moveDown(0.2);
      }
    });
  }

  // ══ PROJECTS
  const projects = sections['PROJECTS'] || [];
  if (projects.length) {
    sectionTitle('Projects');
    projects.forEach(l => { if (l.trim()) projectLine(l); });
  }

  // ══ AWARDS
  const awards = sections['AWARDS'] || [];
  if (awards.length) {
    sectionTitle('Awards');
    awards.forEach(line => {
      const t = stripAll(line.trim());
      if (!t) return;
      const clean = t.replace(/^[•\-*]+\s*/, '').trim();
      if (clean.includes('|') || clean.includes('—')) {
        const sep = clean.includes('|') ? '|' : '—';
        const parts = clean.split(sep);
        rowWithDate(parts.slice(0, -1).join(sep).trim(), parts[parts.length - 1].trim(), true);
      } else {
        body(clean);
      }
    });
  }

  // ══ EDUCATION
  const edu = sections['EDUCATION'] || [];
  if (edu.length) {
    sectionTitle('Education');
    edu.forEach(line => {
      const t = stripAll(line.trim());
      if (!t) return;
      // Education line: match anything with a year range
      const dateMatch = t.match(/(.+?)\s*[|—]\s*((?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec|\d{4})[^|—]*)$/);
      if (dateMatch) {
        rowWithDate(dateMatch[1].trim(), dateMatch[2].trim(), true);
      } else {
        body(t);
      }
    });
  }

  doc.end();
});

return {
  json: { recipientEmail, subject, emailBody },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName: `Resume_${companyName.replace(/\s+/g,'_') || 'Tailored'}.pdf`
    }
  }
};
